pe_object->cap->edit_posts; } return current_user_can($capability); } public function add_row_actions($actions, $post) { $aipkit_options = get_option('aipkit_options', []); $enhancer_list_button_enabled = $aipkit_options['enhancer_settings']['show_list_button'] ?? '1'; if (!in_array((string) $post->post_type, $this->list_screen_post_types, true)) { return $actions; } if ($enhancer_list_button_enabled !== '1') { return $actions; } if ( AIPKit_Role_Manager::user_can_access_module(self::ROW_ASSISTANT_MODULE) && current_user_can('edit_post', $post->ID) ) { $actions['aipkit_ai_enhance'] = sprintf( '<div class="aipkit_enhancer_action">
